import { useQuery } from '@tanstack/react-query'
import type { AllTimeRewardsResponse, WeeklyRewardsResponse } from '@yo-protocol/core'
import { useYoClient } from '../context'

export function useLeaderboard(
  period: 'weekly' | 'allTime',
  tokenAddress: string,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error, refetch } = useQuery<
    WeeklyRewardsResponse | AllTimeRewardsResponse,
    Error
  >({
    queryKey: ['yo-leaderboard', period, tokenAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return period === 'weekly'
        ? client.getWeeklyRewards(tokenAddress)
        : client.getAllTimeRewards(tokenAddress)
    },
    enabled: enabled && !!client,
    staleTime: 5 * 60_000,
  })

  return { data, isLoading, isError, error: error ?? null, refetch }
}
