import { useQuery } from '@tanstack/react-query'
import type { UserVaultPosition, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useUserPosition(
  vault: Address | VaultId,
  account?: Address,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const userAddress = account ?? connectedAddress
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<UserVaultPosition, Error>({
    queryKey: ['yo-user-position', vaultAddress, userAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!userAddress) throw new Error('Account not connected')
      return client.getUserPosition(vaultAddress, userAddress)
    },
    enabled: enabled && !!client && !!userAddress,
    staleTime: 15_000,
    refetchInterval: 30_000,
  })

  return { position: data, isLoading, isError, error: error ?? null, refetch }
}
