import { useQuery } from '@tanstack/react-query'
import type { VaultStatsItem } from '@yo-protocol/core'
import { useYoClient } from '../context'

export function useVaults(options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error } = useQuery<VaultStatsItem[], Error>({
    queryKey: ['yo-vaults'],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getVaults({ secondary: false })
    },
    enabled: enabled && !!client,
    staleTime: 60_000,
  })

  return { vaults: data ?? [], isLoading, isError, error: error ?? null }
}
