import { useQuery } from '@tanstack/react-query'
import type { VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function usePreviewRedeem(
  vault: Address | VaultId,
  shares: bigint | undefined,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<bigint, Error>({
    queryKey: ['yo-preview-redeem', vaultAddress, shares?.toString(), client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.previewRedeem(vaultAddress, shares!)
    },
    enabled: enabled && !!client && shares !== undefined && shares > 0n,
    staleTime: 15_000,
  })

  return { assets: data, isLoading, isError, error: error ?? null, refetch }
}
