'use client'

import { createYoClient, isSupportedChain, type SupportedChainId, type YoClient } from '@yo-protocol/core'
import { createContext, type ReactNode, useContext, useMemo } from 'react'
import { useChainId, usePublicClient } from 'wagmi'

interface YieldContextValue {
  ready: boolean
  partnerId?: number
  defaultSlippageBps: number
  onError?: (error: Error) => void
}

const YieldContext = createContext<YieldContextValue>({
  ready: false,
  defaultSlippageBps: 50,
})

export interface YieldProviderProps {
  children: ReactNode
  partnerId?: number
  defaultSlippageBps?: number
  onError?: (error: Error) => void
}

/**
 * YieldProvider marks the boundary where @yo-protocol/react hooks can be used.
 * Must be placed inside WagmiProvider and after any SSR guards.
 */
export function YieldProvider({
  children,
  partnerId,
  defaultSlippageBps = 50,
  onError,
}: YieldProviderProps) {
  const value = useMemo<YieldContextValue>(
    () => ({ ready: true, partnerId, defaultSlippageBps, onError }),
    [partnerId, defaultSlippageBps, onError],
  )

  return <YieldContext.Provider value={value}>{children}</YieldContext.Provider>
}

/**
 * Hook to access YieldProvider config (partnerId, slippage, onError).
 */
export function useYieldConfig() {
  const ctx = useContext(YieldContext)
  if (!ctx.ready) {
    throw new Error('useYieldConfig must be used within a YieldProvider')
  }
  return ctx
}

/**
 * Hook that creates and returns the YoClient.
 * Returns null when providers aren't ready.
 */
export function useYoClient(): YoClient | null {
  const { ready, partnerId } = useContext(YieldContext)
  const chainId = useChainId()
  const publicClient = usePublicClient()

  return useMemo(() => {
    if (!ready || !isSupportedChain(chainId) || !publicClient) {
      return null
    }

    return createYoClient({
      chainId: chainId as SupportedChainId,
      partnerId,
      publicClients: {
        [chainId]: publicClient,
      } as Partial<Record<SupportedChainId, typeof publicClient>>,
    })
  }, [ready, chainId, publicClient, partnerId])
}
