import { VAULTS, type VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'

function isVaultId(value: string): value is VaultId {
  return value in VAULTS
}

export function resolveVaultAddress(vault: Address | VaultId): Address {
  if (isVaultId(vault)) {
    return VAULTS[vault].address as Address
  }
  return vault
}
