import { useQuery } from '@tanstack/react-query'
import type { UserRewardsByAssetResponse } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useUserRewards(
  tokenAddress?: string,
  user?: Address,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const account = user ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<UserRewardsByAssetResponse, Error>({
    queryKey: ['yo-user-rewards', account, tokenAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')
      return client.getUserRewardsByAsset(account, tokenAddress)
    },
    enabled: enabled && !!client && !!account,
    staleTime: 2 * 60_000,
  })

  return { rewards: data, isLoading, isError, error: error ?? null, refetch }
}
