import { YO_GATEWAY_ADDRESS } from '@yo-protocol/core'
import { useCallback, useEffect, useState } from 'react'
import { maxUint256, type Address, type Hash } from 'viem'
import { useAccount, useSendTransaction, useWaitForTransactionReceipt } from 'wagmi'
import { useYoClient } from '../context'

export interface UseApproveOptions {
  token: Address
  spender?: Address
  onSubmitted?: (hash: Hash) => void
  onConfirmed?: (hash: Hash) => void
  onError?: (error: Error) => void
}

export function useApprove(options: UseApproveOptions) {
  const { token, spender = YO_GATEWAY_ADDRESS, onSubmitted, onConfirmed, onError } = options
  const client = useYoClient()
  const { address: account } = useAccount()
  const { sendTransactionAsync } = useSendTransaction()

  const [hash, setHash] = useState<Hash | undefined>()
  const [isLoading, setIsLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)

  const { isSuccess } = useWaitForTransactionReceipt({ hash, query: { enabled: !!hash } })

  useEffect(() => {
    if (isSuccess && hash) onConfirmed?.(hash)
  }, [isSuccess, hash, onConfirmed])

  const approve = useCallback(
    async (amount: bigint): Promise<Hash> => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')

      setIsLoading(true)
      setError(null)

      try {
        const tx = client.prepareApprove({ token, spender, amount })
        const txHash = await sendTransactionAsync({ to: tx.to, data: tx.data, value: tx.value })
        setHash(txHash)
        onSubmitted?.(txHash)
        return txHash
      } catch (err) {
        const e = err instanceof Error ? err : new Error('Approval failed')
        setError(e)
        onError?.(e)
        throw e
      } finally {
        setIsLoading(false)
      }
    },
    [client, account, token, spender, sendTransactionAsync, onSubmitted, onError],
  )

  const approveMax = useCallback(() => approve(maxUint256), [approve])

  const reset = useCallback(() => {
    setHash(undefined)
    setError(null)
    setIsLoading(false)
  }, [])

  return { approve, approveMax, isLoading, isError: !!error, error, isSuccess, hash, reset }
}
