import { useQuery } from '@tanstack/react-query'
import type { MerklCampaign, MerklCampaignStatus } from '@yo-protocol/core'
import { useYoClient } from '../context'

export function useMerklCampaigns(options?: { status?: MerklCampaignStatus; enabled?: boolean }) {
  const { status, enabled = true } = options ?? {}
  const client = useYoClient()

  const { data, isLoading, isError, error, refetch } = useQuery<MerklCampaign[], Error>({
    queryKey: ['merkl-campaigns', status, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getMerklCampaigns({ status })
    },
    enabled: enabled && !!client,
    staleTime: 60_000,
    refetchInterval: 120_000,
  })

  return { campaigns: data ?? [], isLoading, isError, error: error ?? null, refetch }
}
