import { useQuery } from '@tanstack/react-query'
import type { GlobalVaultHistoryResponse, VaultActivityFilters, VaultHistoryResponse, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export interface UseVaultTransactionHistoryOptions {
  limit?: number
  cursor?: number
  filters?: VaultActivityFilters
  allNetworks?: boolean
  enabled?: boolean
}

export function useVaultTransactionHistory(
  vault: Address | VaultId,
  options?: UseVaultTransactionHistoryOptions,
) {
  const { limit, cursor, filters, allNetworks = false, enabled = true } = options ?? {}
  const client = useYoClient()
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<VaultHistoryResponse | GlobalVaultHistoryResponse, Error>({
    queryKey: ['yo-vault-tx-history', vaultAddress, allNetworks, cursor, limit, filters, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (allNetworks) {
        return client.getVaultHistoryAllNetworks(vaultAddress, { cursor, limit, filters })
      }
      return client.getVaultHistory(vaultAddress, limit)
    },
    enabled: enabled && !!client,
    staleTime: 30_000,
  })

  return { history: data, isLoading, isError, error: error ?? null, refetch }
}
