import { useQuery } from '@tanstack/react-query'
import type { TokenAllowance } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'

export function useAllowance(
  token: Address | undefined,
  spender: Address | undefined,
  owner?: Address,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const ownerAddress = owner ?? connectedAddress

  const { data, isLoading, isError, error, refetch } = useQuery<TokenAllowance, Error>({
    queryKey: ['yo-allowance', token, ownerAddress, spender, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!token || !ownerAddress || !spender) throw new Error('Missing parameters')
      return client.getAllowance(token, ownerAddress, spender)
    },
    enabled: enabled && !!client && !!token && !!ownerAddress && !!spender,
    staleTime: 15_000,
  })

  return { allowance: data, isLoading, isError, error: error ?? null, refetch }
}
