import { useQueryClient } from '@tanstack/react-query'
import type { VaultId } from '@yo-protocol/core'
import { useCallback, useEffect, useState } from 'react'
import type { Address, Hash } from 'viem'
import { useAccount, useSendTransaction, useSwitchChain, useWaitForTransactionReceipt } from 'wagmi'
import { useYieldConfig, useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export type DepositStep = 'idle' | 'switching-chain' | 'approving' | 'depositing' | 'waiting' | 'success' | 'error'

export interface UseDepositOptions {
  vault: Address | VaultId
  slippageBps?: number
  onSubmitted?: (hash: Hash) => void
  onConfirmed?: (hash: Hash) => void
  onError?: (error: Error) => void
}

export function useDeposit(options: UseDepositOptions) {
  const { defaultSlippageBps, onError: globalOnError } = useYieldConfig()
  const { vault, slippageBps = defaultSlippageBps, onSubmitted, onConfirmed, onError } = options
  const client = useYoClient()
  const { address: account, chainId: walletChainId } = useAccount()
  const queryClient = useQueryClient()
  const vaultAddress = resolveVaultAddress(vault)
  const { switchChainAsync } = useSwitchChain()
  const { sendTransactionAsync } = useSendTransaction()

  const [hash, setHash] = useState<Hash | undefined>()
  const [approveHash, setApproveHash] = useState<Hash | undefined>()
  const [step, setStep] = useState<DepositStep>('idle')
  const [error, setError] = useState<Error | null>(null)

  const { isSuccess } = useWaitForTransactionReceipt({ hash, query: { enabled: !!hash } })

  useEffect(() => {
    if (isSuccess && hash) {
      setStep('success')
      queryClient.invalidateQueries({ queryKey: ['yo-user-position', vaultAddress, account] })
      queryClient.invalidateQueries({ queryKey: ['yo-vault-state', vaultAddress] })
      queryClient.invalidateQueries({ queryKey: ['yo-token-balance'] })
      queryClient.invalidateQueries({ queryKey: ['yo-share-balance'] })
      onConfirmed?.(hash)
    }
  }, [isSuccess, hash, queryClient, vaultAddress, account, onConfirmed])

  const deposit = useCallback(
    async (params: { token: Address; amount: bigint; chainId?: number }): Promise<Hash> => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')

      setStep('idle')
      setError(null)

      try {
        // Switch chain if needed
        if (params.chainId && walletChainId !== params.chainId) {
          setStep('switching-chain')
          await switchChainAsync({ chainId: params.chainId })
        }

        // Prepare deposit with approval (handles allowance check internally)
        setStep('approving')
        const txs = await client.prepareDepositWithApproval({
          vault: vaultAddress,
          token: params.token,
          owner: account,
          recipient: account,
          amount: params.amount,
          slippageBps,
          chainId: params.chainId,
        })

        // Send approve tx if present
        if (txs.length > 1) {
          const approveTx = txs[0]!
          const appHash = await sendTransactionAsync({ to: approveTx.to, data: approveTx.data, value: approveTx.value })
          setApproveHash(appHash)
          await client.waitForTransaction(appHash)
        }

        // Send deposit tx
        setStep('depositing')
        const depositTx = txs[txs.length - 1]!
        const depositHash = await sendTransactionAsync({ to: depositTx.to, data: depositTx.data, value: depositTx.value })
        setHash(depositHash)
        setStep('waiting')
        onSubmitted?.(depositHash)
        return depositHash
      } catch (err) {
        const e = err instanceof Error ? err : new Error('Deposit failed')
        setStep('error')
        setError(e)
        onError?.(e)
        globalOnError?.(e)
        throw e
      }
    },
    [client, account, walletChainId, vaultAddress, slippageBps, switchChainAsync, sendTransactionAsync, onSubmitted, onError, globalOnError],
  )

  const reset = useCallback(() => {
    setHash(undefined)
    setApproveHash(undefined)
    setError(null)
    setStep('idle')
  }, [])

  return {
    deposit,
    step,
    isLoading: step !== 'idle' && step !== 'success' && step !== 'error',
    isError: step === 'error',
    error,
    isSuccess,
    hash,
    approveHash,
    reset,
  }
}
