import { useQuery } from '@tanstack/react-query'
import type { VaultId, VaultState } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useVaultState(vault: Address | VaultId, options?: { enabled?: boolean }) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<VaultState, Error>({
    queryKey: ['yo-vault-state', vaultAddress, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      return client.getVaultState(vaultAddress)
    },
    enabled: enabled && !!client,
    staleTime: 30_000,
    refetchInterval: 60_000,
  })

  return { vaultState: data, isLoading, isError, error: error ?? null, refetch }
}
