import { useQuery } from '@tanstack/react-query'
import type { UserPerformance, VaultId } from '@yo-protocol/core'
import type { Address } from 'viem'
import { useAccount } from 'wagmi'
import { useYoClient } from '../context'
import { resolveVaultAddress } from '../utils/vault'

export function useUserPerformance(
  vault: Address | VaultId,
  user?: Address,
  options?: { enabled?: boolean },
) {
  const { enabled = true } = options ?? {}
  const client = useYoClient()
  const { address: connectedAddress } = useAccount()
  const account = user ?? connectedAddress
  const vaultAddress = resolveVaultAddress(vault)

  const { data, isLoading, isError, error, refetch } = useQuery<UserPerformance, Error>({
    queryKey: ['yo-user-performance', vaultAddress, account, client?.chainId],
    queryFn: () => {
      if (!client) throw new Error('Client not available')
      if (!account) throw new Error('Account not connected')
      return client.getUserPerformance(vaultAddress, account)
    },
    enabled: enabled && !!client && !!account,
    staleTime: 30_000,
    refetchInterval: 60_000,
  })

  return { performance: data, isLoading, isError, error: error ?? null, refetch }
}
